import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

export default function Home() {
  const [featured, setFeatured] = useState([]);

  useEffect(() => {
    fetch('http://localhost:5000/api/products')
      .then(r => r.json())
      .then(setFeatured)
      .catch(() => setFeatured([]));
  }, []);

  return (
    <div>
      <section className="hero">
        <h2>Welcome to Green Nursery</h2>
        <p>Discover beautiful indoor and outdoor plants to brighten your space.</p>
        <Link to="/products" className="btn">Shop Plants</Link>
      </section>

      <section>
        <h3>Featured Plants</h3>
        <div className="grid">
          {featured.slice(0, 4).map(p => (
            <div className="card" key={p._id}>
              {p.imagePath && <img src={`http://localhost:5000${p.imagePath}`} alt={p.name} />}
              <h4>{p.name}</h4>
              <p className="price">${p.price}</p>
              <Link to={`/products/${p._id}`} className="small">View</Link>
            </div>
          ))}
        </div>
      </section>
    </div>
  );
}
